import{_ as E,C as h,o as e,c as u,j as t,E as i,w as a,b as n,a4 as o,a3 as s}from"./chunks/framework.CS9vaShW.js";const f=JSON.parse('{"title":"A股高频行情接入链路（一）：交易所行情如何到达券商","description":"梳理A股行情从交易所撮合结果、行情发布系统、接入网络到券商行情接收节点的完整链路，以及各环节的故障风险和验证方法。","frontmatter":{"title":"A股高频行情接入链路（一）：交易所行情如何到达券商","category":"量化交易系统","tags":["高频交易","A股行情","行情接入","交易所","券商","低延迟网络"],"date":"2026-07-10T00:00:00.000Z","description":"梳理A股行情从交易所撮合结果、行情发布系统、接入网络到券商行情接收节点的完整链路，以及各环节的故障风险和验证方法。","wordCount":4290},"headers":[],"relativePath":"posts/a-share-market-data-infrastructure-1.md","filePath":"posts/a-share-market-data-infrastructure-1.md","lastUpdated":1784048876000}'),p={name:"posts/a-share-market-data-infrastructure-1.md"};function B(A,l,b,c,_,m){const r=h("Mermaid"),d=h("ClientOnly");return e(),u("div",null,[l[4]||(l[4]=t("p",null,"本文从交易所产生市场事件开始，沿着行情发布系统、交易所接入网络和券商行情网关，一直讲到券商收到原始行情。重点不是行情程序如何解码或构建订单簿，而是先回答一个更基础的问题：量化机构最终使用的行情，在进入券商内部网络之前经历了哪些系统，以及这些系统如何保证数据来源、完整性和可恢复性。",-1)),i(d,null,{default:a(()=>[(e(),n(o,null,{default:a(()=>[i(r,{id:"mermaid-3",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20ME%5B%E4%BA%A4%E6%98%93%E6%89%80%E6%92%AE%E5%90%88%E7%B3%BB%E7%BB%9F%5D%20--%3E%20MP%5B%E4%BA%A4%E6%98%93%E6%89%80%E8%A1%8C%E6%83%85%E5%8F%91%E5%B8%83%E7%B3%BB%E7%BB%9F%5D%0A%20%20%20%20MP%20--%3E%20GA%5B%E8%A1%8C%E6%83%85%E7%BD%91%E5%85%B3%E6%88%96%E5%8F%91%E5%B8%83%E8%8A%82%E7%82%B9%20A%5D%0A%20%20%20%20MP%20--%3E%20GB%5B%E8%A1%8C%E6%83%85%E7%BD%91%E5%85%B3%E6%88%96%E5%8F%91%E5%B8%83%E8%8A%82%E7%82%B9%20B%5D%0A%20%20%20%20GA%20--%3E%20LA%5B%E4%BA%A4%E6%98%93%E6%89%80%E6%8E%A5%E5%85%A5%E9%93%BE%E8%B7%AF%20A%5D%0A%20%20%20%20GB%20--%3E%20LB%5B%E4%BA%A4%E6%98%93%E6%89%80%E6%8E%A5%E5%85%A5%E9%93%BE%E8%B7%AF%20B%5D%0A%20%20%20%20LA%20--%3E%20BA%5B%E5%88%B8%E5%95%86%E8%A1%8C%E6%83%85%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20A%5D%0A%20%20%20%20LB%20--%3E%20BB%5B%E5%88%B8%E5%95%86%E8%A1%8C%E6%83%85%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20B%5D%0A%20%20%20%20BA%20--%3E%20BUS%5B%E5%88%B8%E5%95%86%E5%86%85%E9%83%A8%E8%A1%8C%E6%83%85%E6%80%BB%E7%BA%BF%5D%0A%20%20%20%20BB%20--%3E%20BUS%0A"})]),fallback:a(()=>[...l[0]||(l[0]=[t("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),l[5]||(l[5]=s('<blockquote><p>本篇范围：交易所撮合结果成为行情消息，直到券商行情接入节点收到数据。券商内部 UDP 组播、Colo 网络和服务器网卡在下一篇讨论；网卡之后的行情程序处理放在后续系列。</p></blockquote><h2 id="_1-为什么先研究交易所到券商" tabindex="-1">1. 为什么先研究交易所到券商 <a class="header-anchor" href="#_1-为什么先研究交易所到券商" aria-label="Permalink to &quot;1. 为什么先研究交易所到券商&quot;">​</a></h2><p>行情程序出现跳号、断流或延迟突增时，问题不一定发生在行情程序内部。数据可能在更早的位置已经缺失：</p><ul><li>交易所行情会话异常；</li><li>券商接入链路中断；</li><li>券商行情接入节点积压；</li><li>主备节点共享同一个上游故障点；</li><li>券商收到的数据本身已经不完整。</li></ul><p>如果不了解上游链路，系统只能看到“本地少了一条消息”，却无法判断消息究竟是交易所未发布、链路未送达，还是券商未接收。</p><p>因此，行情可靠性不是从订单簿程序开始，而是从行情源、接入权限、通信链路和接收节点开始。</p><h2 id="_2-本篇的系统边界" tabindex="-1">2. 本篇的系统边界 <a class="header-anchor" href="#_2-本篇的系统边界" aria-label="Permalink to &quot;2. 本篇的系统边界&quot;">​</a></h2><p>本文涉及四类角色：</p><table tabindex="0"><thead><tr><th>角色</th><th>主要职责</th><th>本文关注点</th></tr></thead><tbody><tr><td>交易所撮合系统</td><td>接收申报并形成成交结果</td><td>产生委托、撤单、成交等市场事件</td></tr><tr><td>交易所行情发布系统</td><td>把市场事件转换为行情产品</td><td>消息类型、频道、序号、状态和发布会话</td></tr><tr><td>交易所接入网络</td><td>把行情送到市场参与者</td><td>链路、权限、会话和主备路径</td></tr><tr><td>券商行情接入节点</td><td>接收并验证交易所行情</td><td>会话维护、完整性检查、恢复和原始记录</td></tr></tbody></table><p>本文不讨论：</p><ul><li>券商如何向 Colo 客户发送 UDP 组播；</li><li>量化服务器网卡如何收包；</li><li>A/B 消息如何去重合并；</li><li>Channel 和 Seq 如何驱动订单簿；</li><li>行情解码、标准化和订单簿构建。</li></ul><p>这些内容需要建立在“上游数据已经可靠到达”的前提上，因此放在后续文章。</p><h2 id="_3-撮合系统和行情发布系统不是同一个程序" tabindex="-1">3. 撮合系统和行情发布系统不是同一个程序 <a class="header-anchor" href="#_3-撮合系统和行情发布系统不是同一个程序" aria-label="Permalink to &quot;3. 撮合系统和行情发布系统不是同一个程序&quot;">​</a></h2><p>初学者容易把交易所理解成一台服务器：投资者订单进入交易所，交易所立刻把行情发出来。真实系统通常会明确分离交易处理和行情发布职责。</p>',14)),i(d,null,{default:a(()=>[(e(),n(o,null,{default:a(()=>[i(r,{id:"mermaid-154",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20O%5B%E5%B8%82%E5%9C%BA%E5%8F%82%E4%B8%8E%E8%80%85%E7%94%B3%E6%8A%A5%5D%20--%3E%20M%5B%E4%BA%A4%E6%98%93%E6%89%80%E6%92%AE%E5%90%88%E7%B3%BB%E7%BB%9F%5D%0A%20%20%20%20M%20--%3E%20E%5B%E5%A7%94%E6%89%98%E3%80%81%E6%92%A4%E5%8D%95%E3%80%81%E6%88%90%E4%BA%A4%E3%80%81%E7%8A%B6%E6%80%81%E4%BA%8B%E4%BB%B6%5D%0A%20%20%20%20E%20--%3E%20P%5B%E8%A1%8C%E6%83%85%E5%8F%91%E5%B8%83%E7%B3%BB%E7%BB%9F%5D%0A%20%20%20%20P%20--%3E%20S1%5B%E5%BF%AB%E7%85%A7%E8%A1%8C%E6%83%85%5D%0A%20%20%20%20P%20--%3E%20S2%5B%E9%80%90%E7%AC%94%E5%A7%94%E6%89%98%5D%0A%20%20%20%20P%20--%3E%20S3%5B%E9%80%90%E7%AC%94%E6%88%90%E4%BA%A4%5D%0A%20%20%20%20P%20--%3E%20S4%5B%E5%B8%82%E5%9C%BA%E4%B8%8E%E8%AF%81%E5%88%B8%E7%8A%B6%E6%80%81%5D%0A"})]),fallback:a(()=>[...l[1]||(l[1]=[t("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),l[6]||(l[6]=s('<h3 id="_3-1-撮合系统负责什么" tabindex="-1">3.1 撮合系统负责什么 <a class="header-anchor" href="#_3-1-撮合系统负责什么" aria-label="Permalink to &quot;3.1 撮合系统负责什么&quot;">​</a></h3><p>撮合系统负责处理交易申报，例如：</p><ul><li>接收买卖订单；</li><li>检查申报是否符合交易规则；</li><li>按价格和时间优先等规则撮合；</li><li>形成成交；</li><li>处理撤单；</li><li>更新交易状态。</li></ul><p>它的核心输出不是给量化机构直接使用的网络包，而是一系列有明确先后关系的市场事件。</p><h3 id="_3-2-行情发布系统负责什么" tabindex="-1">3.2 行情发布系统负责什么 <a class="header-anchor" href="#_3-2-行情发布系统负责什么" aria-label="Permalink to &quot;3.2 行情发布系统负责什么&quot;">​</a></h3><p>行情发布系统把市场事件整理成不同的行情产品，并通过规定的接口对外发布。它通常需要处理：</p><ul><li>市场状态；</li><li>证券状态；</li><li>行情快照；</li><li>逐笔委托；</li><li>逐笔成交；</li><li>频道心跳；</li><li>会话心跳；</li><li>可恢复数据的重传。</li></ul><p>行情发布系统存在的原因是，交易处理和数据分发面对的目标不同。撮合系统强调交易规则与状态正确；行情系统强调大量市场参与者能够连续、及时地收到数据。</p><h2 id="_4-券商接入的不是一个模糊的-level-2" tabindex="-1">4. 券商接入的不是一个模糊的“Level-2” <a class="header-anchor" href="#_4-券商接入的不是一个模糊的-level-2" aria-label="Permalink to &quot;4. 券商接入的不是一个模糊的“Level-2”&quot;">​</a></h2><p>“Level-2 行情”只是一个宽泛称呼，不能据此判断具体能收到什么数据。实际接入前需要明确行情产品、市场范围和接口版本。</p><h3 id="_4-1-常见行情类型" tabindex="-1">4.1 常见行情类型 <a class="header-anchor" href="#_4-1-常见行情类型" aria-label="Permalink to &quot;4.1 常见行情类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行情类型</th><th>表达的内容</th><th style="text-align:right;">是否能还原订单级变化</th></tr></thead><tbody><tr><td>快照行情</td><td>某个时刻的盘口和累计统计</td><td style="text-align:right;">通常不能</td></tr><tr><td>逐笔委托</td><td>新增、撤销等订单事件</td><td style="text-align:right;">取决于协议字段</td></tr><tr><td>逐笔成交</td><td>每笔成交及关联信息</td><td style="text-align:right;">取决于协议字段</td></tr><tr><td>市场状态</td><td>集合竞价、连续竞价、休市、闭市等</td><td style="text-align:right;">不直接构建盘口，但决定消息语义</td></tr><tr><td>证券状态</td><td>停牌、复牌、风险警示等</td><td style="text-align:right;">不直接构建盘口，但影响可交易性</td></tr></tbody></table><p>如果只有十档快照，接收端可以看到每个价格档位的聚合数量，但无法知道这些数量由哪些具体订单组成。要构建更精细的本地订单簿，通常需要逐笔委托、逐笔成交以及足够完整的订单标识和事件语义。</p><h3 id="_4-2-接入前必须确认的清单" tabindex="-1">4.2 接入前必须确认的清单 <a class="header-anchor" href="#_4-2-接入前必须确认的清单" aria-label="Permalink to &quot;4.2 接入前必须确认的清单&quot;">​</a></h3><ul><li>行情产品名称；</li><li>覆盖的交易所和证券类型；</li><li>是否包含逐笔委托、逐笔成交和撤单；</li><li>是否包含市场状态和证券状态；</li><li>协议版本及生效日期；</li><li>价格和数量的单位；</li><li>频道划分方式；</li><li>序号重置规则；</li><li>快照和逐笔分别是否支持恢复；</li><li>盘中重新接入时如何同步。</li></ul><p>这里最危险的问题不是完全收不到行情，而是只收到部分产品或字段，程序仍然运行，却误以为数据完整。</p><h2 id="_5-交易所行情网关是什么" tabindex="-1">5. 交易所行情网关是什么 <a class="header-anchor" href="#_5-交易所行情网关是什么" aria-label="Permalink to &quot;5. 交易所行情网关是什么&quot;">​</a></h2><p>行情网关可以理解为交易所对市场参与者提供的标准化接入边界。券商的用户行情系统与行情网关建立会话，接收规定格式的实时行情。</p><p>以上海证券交易所公开的 BINARY 行情网关规范为例，用户行情系统通过 TCP 与行情网关建立会话，登录成功后接收市场状态、快照、逐笔行情和频道心跳；会话中还包含消息序号、心跳和重传机制。该公开接口只是一个具体例子，不能据此推断所有交易所、所有行情产品和所有券商接入方式完全相同。</p><h3 id="_5-1-会话层解决什么问题" tabindex="-1">5.1 会话层解决什么问题 <a class="header-anchor" href="#_5-1-会话层解决什么问题" aria-label="Permalink to &quot;5.1 会话层解决什么问题&quot;">​</a></h3><p>会话层主要负责：</p><ul><li>登录与身份确认；</li><li>协议版本协商；</li><li>判断连接是否仍然存活；</li><li>维护会话消息序号；</li><li>发现连接异常并重建会话；</li><li>对可恢复数据发起请求。</li></ul><p>它解决的是“双方是否在正常通信”，而不是完整代替业务层的逐笔连续性检查。</p><h3 id="_5-2-为什么不能把-tcp-等同于绝不丢数据" tabindex="-1">5.2 为什么不能把 TCP 等同于绝不丢数据 <a class="header-anchor" href="#_5-2-为什么不能把-tcp-等同于绝不丢数据" aria-label="Permalink to &quot;5.2 为什么不能把 TCP 等同于绝不丢数据&quot;">​</a></h3><p>TCP 可以保证一个正常连接内的字节流按序到达，但不能解决全部问题：</p><ul><li>上游应用可能根本没有生成某条业务消息；</li><li>接收程序可能处理过慢，导致上游主动断开；</li><li>连接中断后需要重新建立会话和恢复状态；</li><li>业务频道仍需用自己的业务序号判断是否完整；</li><li>券商内部重新封装后，后续链路可能改用 UDP。</li></ul><p>因此，传输协议可靠不等于整条行情业务链路天然可靠。</p><h2 id="_6-交易所到券商之间的网络" tabindex="-1">6. 交易所到券商之间的网络 <a class="header-anchor" href="#_6-交易所到券商之间的网络" aria-label="Permalink to &quot;6. 交易所到券商之间的网络&quot;">​</a></h2><p>交易所行情不会经过普通互联网随意传输。市场参与者通常通过受控的接入网络、专用线路或交易所认可的技术服务体系连接行情网关。</p><p>从系统设计角度，需要关注的不是线路名称，而是以下属性：</p><ul><li>是否存在 A/B 两条物理路径；</li><li>两条路径是否经过独立设备；</li><li>是否共享同一运营商、机房或光缆；</li><li>链路带宽和峰值包速率是否足够；</li><li>链路错误、抖动和中断是否可监控；</li><li>主备切换后行情会话如何恢复；</li><li>网络安全策略是否可能阻断会话或重传。</li></ul><h3 id="_6-1-两条线-不一定是真冗余" tabindex="-1">6.1 “两条线”不一定是真冗余 <a class="header-anchor" href="#_6-1-两条线-不一定是真冗余" aria-label="Permalink to &quot;6.1 “两条线”不一定是真冗余&quot;">​</a></h3><p>下面的结构看起来有两条链路，但仍有明显单点：</p>',33)),i(d,null,{default:a(()=>[(e(),n(o,null,{default:a(()=>[i(r,{id:"mermaid-527",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20G%5B%E5%8D%95%E4%B8%80%E8%A1%8C%E6%83%85%E7%BD%91%E5%85%B3%E6%88%96%E6%8E%A5%E5%85%A5%E5%87%BA%E5%8F%A3%5D%20--%3E%20L1%5B%E9%93%BE%E8%B7%AF%20A%5D%0A%20%20%20%20G%20--%3E%20L2%5B%E9%93%BE%E8%B7%AF%20B%5D%0A%20%20%20%20L1%20--%3E%20B1%5B%E5%88%B8%E5%95%86%E8%8A%82%E7%82%B9%20A%5D%0A%20%20%20%20L2%20--%3E%20B2%5B%E5%88%B8%E5%95%86%E8%8A%82%E7%82%B9%20B%5D%0A"})]),fallback:a(()=>[...l[2]||(l[2]=[t("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),l[7]||(l[7]=t("p",null,"如果单一上游节点故障，两条链路会同时失效。真正的冗余需要分析完整故障域：",-1)),i(d,null,{default:a(()=>[(e(),n(o,null,{default:a(()=>[i(r,{id:"mermaid-531",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20G1%5B%E5%8F%91%E5%B8%83%E8%8A%82%E7%82%B9%20A%5D%20--%3E%20L1%5B%E7%8B%AC%E7%AB%8B%E9%93%BE%E8%B7%AF%20A%5D%20--%3E%20B1%5B%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20A%5D%0A%20%20%20%20G2%5B%E5%8F%91%E5%B8%83%E8%8A%82%E7%82%B9%20B%5D%20--%3E%20L2%5B%E7%8B%AC%E7%AB%8B%E9%93%BE%E8%B7%AF%20B%5D%20--%3E%20B2%5B%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20B%5D%0A"})]),fallback:a(()=>[...l[3]||(l[3]=[t("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),l[8]||(l[8]=s(`<p>实际拓扑是否达到这种独立程度，需要以交易所和券商提供的正式设计为准，不能只根据服务器上有两个接口进行推断。</p><h2 id="_7-券商行情接入节点负责什么" tabindex="-1">7. 券商行情接入节点负责什么 <a class="header-anchor" href="#_7-券商行情接入节点负责什么" aria-label="Permalink to &quot;7. 券商行情接入节点负责什么&quot;">​</a></h2><p>券商行情接入节点是交易所接口和券商内部行情系统之间的边界。它通常接收交易所原始行情，然后把数据交给内部标准化、分发或录制系统。</p><h3 id="_7-1-输入" tabindex="-1">7.1 输入 <a class="header-anchor" href="#_7-1-输入" aria-label="Permalink to &quot;7.1 输入&quot;">​</a></h3><ul><li>交易所实时行情会话；</li><li>行情账户和权限；</li><li>协议版本配置；</li><li>交易日和证券基础信息；</li><li>重传或恢复响应；</li><li>时间同步信号。</li></ul><h3 id="_7-2-输出" tabindex="-1">7.2 输出 <a class="header-anchor" href="#_7-2-输出" aria-label="Permalink to &quot;7.2 输出&quot;">​</a></h3><ul><li>已接收的原始行情消息；</li><li>会话状态；</li><li>频道和业务连续性状态；</li><li>缺口与恢复状态；</li><li>原始行情记录；</li><li>供内部系统使用的行情流。</li></ul><h3 id="_7-3-它负责什么" tabindex="-1">7.3 它负责什么 <a class="header-anchor" href="#_7-3-它负责什么" aria-label="Permalink to &quot;7.3 它负责什么&quot;">​</a></h3><ul><li>建立并维护行情会话；</li><li>检查消息格式和基础校验；</li><li>跟踪连接、心跳和序号；</li><li>发现缺口并执行协议允许的恢复；</li><li>保存足够的原始证据；</li><li>把健康状态传递给下游。</li></ul><h3 id="_7-4-它不负责什么" tabindex="-1">7.4 它不负责什么 <a class="header-anchor" href="#_7-4-它不负责什么" aria-label="Permalink to &quot;7.4 它不负责什么&quot;">​</a></h3><p>券商行情接入节点不一定负责：</p><ul><li>为每个 Colo 客户直接发包；</li><li>给量化机构构建订单簿；</li><li>保证下游交换网络绝不丢包；</li><li>保证所有供应商标准化后的字段仍与交易所原始字段一一对应。</li></ul><p>这些职责可能属于后续的行情分发、标准化或客户接入系统。</p><h2 id="_8-券商接入节点常见的故障" tabindex="-1">8. 券商接入节点常见的故障 <a class="header-anchor" href="#_8-券商接入节点常见的故障" aria-label="Permalink to &quot;8. 券商接入节点常见的故障&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>直接表现</th><th>风险</th><th>解决方向</th></tr></thead><tbody><tr><td>行情会话未登录</td><td>完全没有某类行情</td><td>盘前即不可用</td><td>权限、地址、版本和登录时点检查</td></tr><tr><td>心跳超时或连接断开</td><td>行情突然停止</td><td>下游使用陈旧数据</td><td>自动重连、状态降级、主备切换</td></tr><tr><td>接入程序处理过慢</td><td>延迟上升或被上游断开</td><td>数据积压和缺失</td><td>容量测试、进程隔离、队列监控</td></tr><tr><td>协议版本不匹配</td><td>解码异常或字段错位</td><td>静默数据错误</td><td>版本绑定、灰度验证、原始包留存</td></tr><tr><td>权限不完整</td><td>部分市场或产品缺失</td><td>系统误判数据完整</td><td>盘前产品清单比对</td></tr><tr><td>主备共享单点</td><td>A/B 同时异常</td><td>冗余失效</td><td>绘制真实故障域并拆除共同依赖</td></tr><tr><td>重传不可用</td><td>缺口无法恢复</td><td>下游状态长期不可信</td><td>独立备用源、缓存和重同步方案</td></tr></tbody></table><h3 id="_8-1-最危险的是静默错误" tabindex="-1">8.1 最危险的是静默错误 <a class="header-anchor" href="#_8-1-最危险的是静默错误" aria-label="Permalink to &quot;8.1 最危险的是静默错误&quot;">​</a></h3><p>完全断流通常很容易发现。更危险的是：</p><ul><li>价格倍率错误；</li><li>某种消息类型被过滤；</li><li>新协议字段没有被识别；</li><li>部分频道没有订阅；</li><li>A/B 两个接入节点使用不同配置；</li><li>时间戳来源被错误理解。</li></ul><p>这类问题可能不会导致进程崩溃，却会把错误数据持续交给下游。</p><h2 id="_9-时间同步从上游就必须开始" tabindex="-1">9. 时间同步从上游就必须开始 <a class="header-anchor" href="#_9-时间同步从上游就必须开始" aria-label="Permalink to &quot;9. 时间同步从上游就必须开始&quot;">​</a></h2><p>在券商接入层，至少可能出现以下时间：</p><ul><li>交易所消息中的时间；</li><li>券商网络接口接收时间；</li><li>券商接入程序读取时间；</li><li>券商向内部系统发布时间。</li></ul><p>如果时间定义不清或设备未同步，就无法可靠分析：</p><ul><li>交易所到券商的传播时间；</li><li>A/B 哪一路更快；</li><li>延迟来自网络还是程序；</li><li>主备切换前后的时间变化；</li><li>某条异常消息究竟先发生还是后发生。</li></ul><p>需要为每个时间戳记录：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>时间戳名称</span></span>
<span class="line"><span>生成设备</span></span>
<span class="line"><span>生成位置</span></span>
<span class="line"><span>使用的时钟源</span></span>
<span class="line"><span>精度与分辨率</span></span>
<span class="line"><span>是否可能回跳</span></span>
<span class="line"><span>是否与其他设备可比较</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>延迟计算还应使用单调时钟，避免墙上时间调整造成负延迟或超时判断错误。</p><h2 id="_10-上游链路应该监控什么" tabindex="-1">10. 上游链路应该监控什么 <a class="header-anchor" href="#_10-上游链路应该监控什么" aria-label="Permalink to &quot;10. 上游链路应该监控什么&quot;">​</a></h2><h3 id="_10-1-行情产品层" tabindex="-1">10.1 行情产品层 <a class="header-anchor" href="#_10-1-行情产品层" aria-label="Permalink to &quot;10.1 行情产品层&quot;">​</a></h3><ul><li>当前收到哪些市场和产品；</li><li>每类消息的数量；</li><li>是否收到市场状态和频道心跳；</li><li>盘前预期产品与实际产品是否一致。</li></ul><h3 id="_10-2-会话层" tabindex="-1">10.2 会话层 <a class="header-anchor" href="#_10-2-会话层" aria-label="Permalink to &quot;10.2 会话层&quot;">​</a></h3><ul><li>登录状态；</li><li>会话建立和断开次数；</li><li>心跳超时；</li><li>会话消息序号；</li><li>上游主动注销原因；</li><li>重传请求和结果。</li></ul><h3 id="_10-3-业务层" tabindex="-1">10.3 业务层 <a class="header-anchor" href="#_10-3-业务层" aria-label="Permalink to &quot;10.3 业务层&quot;">​</a></h3><ul><li>各频道最新业务序号；</li><li>缺口、重复和回退；</li><li>快照与逐笔活跃状态；</li><li>交易阶段是否合理；</li><li>A/B 节点消息数量差异。</li></ul><h3 id="_10-4-基础设施层" tabindex="-1">10.4 基础设施层 <a class="header-anchor" href="#_10-4-基础设施层" aria-label="Permalink to &quot;10.4 基础设施层&quot;">​</a></h3><ul><li>链路状态；</li><li>端口错误；</li><li>峰值流量和包速率；</li><li>CPU、内存和接收队列压力；</li><li>时间同步状态；</li><li>原始记录是否持续写入。</li></ul><h2 id="_11-如何验证交易所到券商链路" tabindex="-1">11. 如何验证交易所到券商链路 <a class="header-anchor" href="#_11-如何验证交易所到券商链路" aria-label="Permalink to &quot;11. 如何验证交易所到券商链路&quot;">​</a></h2><h3 id="_11-1-盘前验证" tabindex="-1">11.1 盘前验证 <a class="header-anchor" href="#_11-1-盘前验证" aria-label="Permalink to &quot;11.1 盘前验证&quot;">​</a></h3><ol><li>验证交易日和协议版本；</li><li>验证行情账户和产品权限；</li><li>验证 A/B 节点都能建立会话；</li><li>验证市场状态和频道心跳；</li><li>对比两个节点的消息数量和关键字段；</li><li>检查时间同步；</li><li>确认原始行情录制已启动；</li><li>行情健康状态通过后才允许下游进入就绪状态。</li></ol><h3 id="_11-2-故障注入" tabindex="-1">11.2 故障注入 <a class="header-anchor" href="#_11-2-故障注入" aria-label="Permalink to &quot;11.2 故障注入&quot;">​</a></h3><ul><li>主动断开一条接入链路；</li><li>重启一个接入节点；</li><li>模拟会话心跳超时；</li><li>模拟协议版本不匹配；</li><li>模拟某个频道短暂缺口；</li><li>验证重传、切换和状态上报；</li><li>验证异常期间不会把“连接仍在”误报为“行情完整”。</li></ul><h3 id="_11-3-盘后对账" tabindex="-1">11.3 盘后对账 <a class="header-anchor" href="#_11-3-盘后对账" aria-label="Permalink to &quot;11.3 盘后对账&quot;">​</a></h3><ul><li>对比 A/B 原始消息数量；</li><li>统计每个频道缺口和重传；</li><li>检查会话中断时间；</li><li>分析延迟分布而不只看平均值；</li><li>保存协议、配置和节点版本；</li><li>对异常时间段执行原始消息回放。</li></ul><h2 id="_12-关键设计取舍" tabindex="-1">12. 关键设计取舍 <a class="header-anchor" href="#_12-关键设计取舍" aria-label="Permalink to &quot;12. 关键设计取舍&quot;">​</a></h2><h3 id="_12-1-低延迟和可恢复性" tabindex="-1">12.1 低延迟和可恢复性 <a class="header-anchor" href="#_12-1-低延迟和可恢复性" aria-label="Permalink to &quot;12.1 低延迟和可恢复性&quot;">​</a></h3><p>为了降低延迟，可以减少缓存和处理层次；但缓存过少会降低突发吸收和恢复能力。接入层不能只追求最快转发，还要保留足够的原始数据和状态，才能在下游发现问题时追溯原因。</p><h3 id="_12-2-主备热运行和资源成本" tabindex="-1">12.2 主备热运行和资源成本 <a class="header-anchor" href="#_12-2-主备热运行和资源成本" aria-label="Permalink to &quot;12.2 主备热运行和资源成本&quot;">​</a></h3><p>冷备节点成本低，但故障后需要建立会话、同步状态和追赶数据。高频场景通常更需要主备节点持续热运行，使备用源始终知道自己是否完整，而不是故障发生后才启动。</p><h3 id="_12-3-原始协议和内部统一协议" tabindex="-1">12.3 原始协议和内部统一协议 <a class="header-anchor" href="#_12-3-原始协议和内部统一协议" aria-label="Permalink to &quot;12.3 原始协议和内部统一协议&quot;">​</a></h3><p>保留原始协议有利于审计和精确追溯，但会增加下游适配复杂度。转换成统一协议便于内部使用，却引入字段丢失、语义转换和版本管理风险。后续文章会单独讨论券商内部如何选择透传、标准化或重建后分发。</p><h2 id="_13-仍需向交易所或券商确认的问题" tabindex="-1">13. 仍需向交易所或券商确认的问题 <a class="header-anchor" href="#_13-仍需向交易所或券商确认的问题" aria-label="Permalink to &quot;13. 仍需向交易所或券商确认的问题&quot;">​</a></h2><p>以下信息不能通过通用架构推断，必须以正式接口文档和现场拓扑为准：</p><ul><li>实际行情产品及协议版本；</li><li>A/B 接入节点是否对应独立上游发布节点；</li><li>两条线路是否真正物理独立；</li><li>逐笔和快照的恢复机制；</li><li>可恢复历史长度；</li><li>券商接入节点是否重新编号或过滤消息；</li><li>券商内部是否保留交易所原始 Channel 和业务 Seq；</li><li>时间戳的生成位置；</li><li>市场参与者可获得哪些上游监控信息。</li></ul><p>未获得正式资料前，这些内容都应标记为“未确认”，不能写成既定事实。</p><h2 id="_14-下一篇-券商如何把行情送入-colo" tabindex="-1">14. 下一篇：券商如何把行情送入 Colo <a class="header-anchor" href="#_14-下一篇-券商如何把行情送入-colo" aria-label="Permalink to &quot;14. 下一篇：券商如何把行情送入 Colo&quot;">​</a></h2><p>券商收到交易所行情后，通常还要经过内部行情总线、分发节点、UDP 组播、A/B 交换网络和 Colo 接入交换机，最终到达量化服务器网卡。</p><p>下一篇将讨论：</p><ul><li>券商原始透传、标准化和订单簿输出的区别；</li><li>UDP 组播为什么适合一对多行情分发；</li><li>A/B 双路、双节点和双源如何区分；</li><li>VLAN、IGMP、交换机缓存和微突发；</li><li>光纤、光模块和服务器网卡前的故障定位。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://www.sse.com.cn/services/tradingtech/data/c/10824278/files/0bd5b8920cef4b238b7bd398e734ce18.pdf" target="_blank" rel="noreferrer">上海证券交易所行情网关 BINARY 数据接口规范</a></li></ul><blockquote><p>本文仅为个人学习笔记和系统架构设计整理，不构成任何投资建议或交易建议。高频量化交易系统涉及市场风险、技术风险、合规风险和运维风险，任何实盘部署都应经过充分测试、独立验证和风险评估。</p></blockquote>`,61))])}const P=E(p,[["render",B]]);export{f as __pageData,P as default};
